def simulate_auth_middleware(f):
    """
    Simulates authentication middleware that has already verified the user.
    In production, this would be replaced by actual JWT/session verification.
    Sets g.current_user with authenticated user information.
    """
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Simulate that auth middleware has already verified the token
        # and placed user info in the request context
        user_id = request.headers.get("X-User-Id", "user_001")
        user = USERS_DB.get(user_id)
        if not user:
            return jsonify({"error": "Authentication required"}), 401
        g.current_user = user
        return f(*args, **kwargs)
    return decorated_function


def check_tenant_access(user, invoice):
    """
    Verify the user belongs to the same tenant as the invoice.
    Prevents cross-tenant data access.
    """
    return user["tenant_id"] == invoice["tenant_id"]


def check_role_access(user, invoice):
    """
    Verify the user's role is authorized to download invoices.
    """
    return user["role"] in invoice["accessible_roles"]


def check_resource_ownership(user, invoice):
    """
    Check if the user owns the invoice or has elevated privileges.
    Regular owners can only access their own invoices.
    Admins and billing_managers can access all invoices within their tenant.
    """
    elevated_roles = {"admin", "billing_manager"}
    if user["role"] in elevated_roles:
        return True
    # Owners can only download their own invoices
    return user["id"] == invoice["user_id"]


def check_invoice_downloadable(user, invoice):
    """
    Check if the invoice status allows downloading.
    Admins can download invoices in any status.
    Other roles can only download finalized invoices.
    """
    if user["role"] == "admin":
        return invoice["status"] in ADMIN_DOWNLOADABLE_STATUSES
    return invoice["status"] in DOWNLOADABLE_STATUSES


