def sanitize_invoice_id(invoice_id):
    """
    Validate and sanitize the invoice ID parameter.
    Prevents injection and ensures it's a valid positive integer.
    """
    try:
        invoice_id = int(invoice_id)
        if invoice_id <= 0:
            return None
        if invoice_id > 2**31 - 1:  # Prevent integer overflow
            return None
        return invoice_id
    except (ValueError, TypeError):
        return None


def log_access_attempt(user, invoice_id, success, reason=""):
    """
    Log all access attempts for audit trail.
    In production, this would write to a secure audit log.
    """
    timestamp = datetime.utcnow().isoformat()
    status = "SUCCESS" if success else "DENIED"
    print(
        f"[AUDIT] {timestamp} | {status} | user={user['id']} | "
        f"tenant={user['tenant_id']} | role={user['role']} | "
        f"invoice={invoice_id} | reason={reason}"
    )


