@simulate_auth_middleware
def download_invoice(invoice_id):
    """
    Download an invoice PDF by invoice ID.

    Authorization checks performed:
    1. Input validation and sanitization
    2. Resource existence verification
    3. Tenant isolation check
    4. Role-based access control
    5. Resource ownership verification
    6. Invoice status/field-level access control
    """
    user = g.current_user

    # 1. Sanitize and validate the invoice ID
    sanitized_id = sanitize_invoice_id(invoice_id)
    if sanitized_id is None:
        log_access_attempt(user, invoice_id, False, "invalid_invoice_id")
        return jsonify({"error": "Invalid invoice ID format"}), 400

    # 2. Check if the invoice exists
    invoice = INVOICES_DB.get(sanitized_id)
    if invoice is None:
        # Return 404 to avoid leaking information about valid IDs
        # Use the same error message regardless of whether the ID exists
        # in another tenant to prevent enumeration
        log_access_attempt(user, sanitized_id, False, "invoice_not_found")
        return jsonify({"error": "Invoice not found"}), 404

    # 3. Tenant isolation check - CRITICAL
    # Ensure the user can only access invoices within their own tenant
    if not check_tenant_access(user, invoice):
        # Return 404 instead of 403 to prevent tenant enumeration
        log_access_attempt(user, sanitized_id, False, "tenant_mismatch")
        return jsonify({"error": "Invoice not found"}), 404

    # 4. Role-based access control
    # Verify the user's role is permitted to download invoices
    if not check_role_access(user, invoice):
        log_access_attempt(user, sanitized_id, False, "insufficient_role")
        return jsonify({
            "error": "Forbidden: Your role does not have permission to download invoices"
        }), 403

    # 5. Resource ownership check
    # Verify the user owns the invoice or has elevated privileges
    if not check_resource_ownership(user, invoice):
        log_access_attempt(user, sanitized_id, False, "not_owner")
        return jsonify({
            "error": "Forbidden: You do not have access to this invoice"
        }), 403

    # 6. Field-level / status-based access control
    # Check if the invoice's current status allows downloading
